#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
typedef unsigned long long uLL;
inline uLL read()
{
	uLL res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void print(const uLL &p){if(p>9)print(p/10);putchar(p%10+'0');}
const int N=1<<13|7;uLL ans[15];int top,p,qwq[N],stk[N];
int main()
{
	for(int i=0;i<(1<<13);++i)
	{
		int tmp=0,I=i;while(I)I^=(I&-I),++tmp;
		if(tmp==6)qwq[++p]=i;
	}
	int n=read();rep(0,12,i)
	{
		drep(n,1,j)if((qwq[j]>>i)&1)stk[++top]=j;if(!top)break;
		putchar('?');printf(" %d",top);while(top)printf(" %d",stk[top--]);putchar('\n');fflush(stdout); ans[i]=read();
	}
	putchar('!');rep(1,n,i)
	{
		uLL tmp=0;rep(0,12,j)if(!((qwq[i]>>j)&1))tmp|=ans[j];
		putchar(' ');print(tmp);
	}
	putchar('\n');
}
